+  // Exitflag
+  int64_t exitflag_;
+
+  void initializeProblemImpl(
+    const Eigen::MatrixXd & P, const Eigen::MatrixXd & A, const std::vector<double> & q,
+    const std::vector<double> & l, const std::vector<double> & u) override;
+
+  void initializeCSCProblemImpl(
