+  /**
+   * find forward collision segment by stop line
+   *                s
+   *  | = | = | = | s | = |
+   *  0   1   2   3 s  4   5
+   *
+   **/
+  auto path = test::generatePath(0.0, 0.0, 5.0, 0.0, 6);
