+template <>
+std::array<double, 36> parse(const YAML::Node & node)
+{
+  std::array<double, 36> msg{};
+  const auto cov = node.as<std::vector<double>>();
+  for (size_t i = 0; i < 36; ++i) {
+    msg[i] = cov.at(i);
+  }
+  return msg;
+}
