+template <>
+Point parse(const YAML::Node & node)
+{
+  Point geom_point;
+  geom_point.x = node["x"].as<double>();
+  geom_point.y = node["y"].as<double>();
+  geom_point.z = node["z"].as<double>();
+  return geom_point;
+}
+
+template <>
+std::vector<Point> parse(const YAML::Node & node)
+{
+  std::vector<Point> geom_points;
+
+  std::transform(
+    node.begin(), node.end(), std::back_inserter(geom_points), [&](const YAML::Node & input) {
+      Point point;
+      point.x = input["x"].as<double>();
+      point.y = input["y"].as<double>();
+      point.z = input["z"].as<double>();
+      return point;
+    });
+
+  return geom_points;
+}
