+
+  const auto & points = node;
+  path_points.reserve(points.size());
+  std::transform(
+    points.begin(), points.end(), std::back_inserter(path_points), [&](const YAML::Node & input) {
+      PathPointWithLaneId point;
+      if (!input["point"]) {
+        return point;
